#include<bits/stdc++.h>
using namespace std;
long long n,m,ans,dp[1024][1024][3],a[110],s[1024];
int main()
{
    scanf("%lld%lld",&n,&m);
    for(int i=0;i<n;i++)
    {
        for(int j=0;j<m;j++)
        {
            char ch;
            cin>>ch;
            a[i]=a[i]*2+(ch=='H');
        }
    }
    if(n==1)
    {
        for(int i=0;i<(1<<m);i++)
        {
            if(i&(i<<1)||i&(i<<2))
            {
                continue;
            }
            ans=max(ans,(long long)(__builtin_popcount(i)));
        }
        printf("%lld",ans);
        return 0;
    }
    for(int i=0;i<(1<<m);i++)
    {
        s[i]=__builtin_popcount(i);
    }
    for(int i=0;i<(1<<m);i++)
    {
        for(int j=0;j<(1<<m);j++)
        {
            if(!(i&j||i&a[0]||j&a[1]||(i&(i<<1))||(i&(i<<2))||(j&(j<<1))||(j&(j<<2))))
            {
                dp[i][j][1]=s[i]+s[j];
            }
        }
    }
    for(int i=2;i<n;i++)
    {
        for(int j=0;j<(1<<m);j++)
        {
            if(j&a[i-1]||(j&(j<<1))||(j&(j<<2)))
            {
                continue;
            }
            for(int k=0;k<(1<<m);k++)
            {
                if(k&a[i]||j&k||(k&(k<<1))||(k&(k<<2)))
                {
                    continue;
                }
                for(int l=0;l<(1<<m);l++)
                {
                    if(j&l||k&l||(l&(l<<1))||(l&(l<<2)))
                    {
                        continue;
                    }
                    dp[j][k][i%3]=max(dp[j][k][i%3],dp[l][j][(i-1)%3]+s[k]);
                }
            }
        }
    }
    long long ans=0;
    for(int i=0;i<(1<<m);i++)
    {
        for(int j=0;j<(1<<m);j++)
        {
            ans=max(ans,dp[i][j][(n-1)%3]);
        }
    }
    printf("%lld",ans);
    return 0;
}
